import { type NextRequest, NextResponse } from "next/server";
import { kv } from "@vercel/kv";
import { computeSessionToken, SESSION_COOKIE } from "@/lib/auth";
import type { UserSession } from "@/lib/kv";

const PUBLIC = ["/login", "/privacy", "/api/auth", "/api/support"];

// Matches UUIDs generated by crypto.randomUUID() for per-user sessions.
// Admin sessions are 64-char lowercase hex and will not match this pattern.
const UUID_RE =
  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/;

export async function middleware(req: NextRequest) {
  const { pathname } = req.nextUrl;

  if (PUBLIC.some((p) => pathname.startsWith(p))) {
    return NextResponse.next();
  }

  const password = process.env.APP_PASSWORD;
  const secret = process.env.AUTH_SECRET;

  // Auth is opt-in — if env vars are not set, allow everything through
  if (!password || !secret) return NextResponse.next();

  const cookie = req.cookies.get(SESSION_COOKIE)?.value;

  if (cookie) {
    if (/^[0-9a-f]{64}$/.test(cookie)) {
      // Admin HMAC session — no KV lookup needed
      const expected = await computeSessionToken(password, secret);
      if (cookie === expected) return NextResponse.next();
    } else if (UUID_RE.test(cookie) && process.env.KV_REST_API_URL) {
      // Per-user session stored in Vercel KV
      try {
        const session = await kv.get<UserSession>(`session:${cookie}`);
        if (session && session.expiresAt > Date.now()) return NextResponse.next();
      } catch {
        // KV unavailable — fall through to redirect
      }
    }
  }

  // API calls get 401; page requests get redirected to login
  if (pathname.startsWith("/api/")) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const url = req.nextUrl.clone();
  url.pathname = "/login";
  url.searchParams.set("from", pathname);
  return NextResponse.redirect(url);
}

export const config = {
  matcher: [
    "/((?!_next/static|_next/image|favicon\\.ico|.*\\.png$|.*\\.ico$|.*\\.mjs$|.*\\.css$|.*\\.map$).*)",
  ],
};
